1	import { Request, Response, NextFunction } from 'express';
2	import crypto from 'crypto';
3	import { getPrisma } from '../config/database';
4	import { Prisma } from '../models/prisma';
5	import { logger } from '../utils/logger';
6	import { IDEMPOTENCY_CONFLICT } from '../utils/errors';
7	
8	const MUTATING_METHODS = new Set(['POST', 'PATCH', 'DELETE']);
9	const TTL_MS = 24 * 60 * 60 * 1000;
10	
11	const SENSITIVE_KEYS = new Set(['accessToken', 'refreshToken', 'token', 'tokenHash', 'password', 'passwordHash']);
12	
13	function redactSecrets(obj: unknown): unknown {
14	  if (obj === null || obj === undefined || typeof obj !== 'object') return obj;
15	  if (Array.isArray(obj)) return obj.map(redactSecrets);
16	  const out: Record<string, unknown> = {};
17	  for (const [k, v] of Object.entries(obj as Record<string, unknown>)) {
18	    out[k] = SENSITIVE_KEYS.has(k) ? '[REDACTED]' : redactSecrets(v);
19	  }
20	  return out;
21	}
22	
23	function buildFingerprint(req: Request): string {
24	  const authHeader = req.headers.authorization;
25	  let actor = 'anonymous';
26	  if (authHeader?.startsWith('Bearer ')) {
27	    try {
28	      const payload = JSON.parse(Buffer.from(authHeader.slice(7).split('.')[1], 'base64').toString());
29	      actor = payload.userId || 'anonymous';
30	    } catch { /* malformed token */ }
31	  }
32	  const method = req.method;
33	  const route = req.originalUrl.replace(/[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}/gi, ':id');
34	  const bodyHash = req.body && Object.keys(req.body).length > 0
35	    ? crypto.createHash('sha256').update(JSON.stringify(req.body, Object.keys(req.body).sort())).digest('hex')
36	    : 'empty';
37	  return crypto.createHash('sha256').update(`${actor}:${method}:${route}:${bodyHash}`).digest('hex');
38	}
39	
40	export async function idempotencyMiddleware(
41	  req: Request,
42	  res: Response,
43	  next: NextFunction,
44	): Promise<void> {
45	  if (!MUTATING_METHODS.has(req.method)) {
46	    next();
47	    return;
48	  }
49	
50	  const idempotencyKey = req.headers['idempotency-key'] as string | undefined;
51	  if (!idempotencyKey) {
52	    res.status(400).json({
53	      statusCode: 400,
54	      code: 'MISSING_IDEMPOTENCY_KEY',
55	      message: 'Idempotency-Key header is required for mutating operations',
56	    });
57	    return;
58	  }
59	
60	  res.setHeader('Idempotency-Key', idempotencyKey);
61	  const fingerprint = buildFingerprint(req);
62	
63	  try {
64	    const prisma = getPrisma();
65	    const existing = await prisma.idempotencyKey.findUnique({ where: { key: idempotencyKey } });
66	
67	    if (existing && existing.expiresAt > new Date()) {
68	      const stored = existing.responseBody as Record<string, unknown>;
69	      const storedFingerprint = stored._fingerprint as string | undefined;
70	
71	      if (storedFingerprint && storedFingerprint !== fingerprint) {
72	        res.status(409).json({
73	          statusCode: 409,
74	          code: IDEMPOTENCY_CONFLICT,
75	          message: 'Idempotency key already used with different request parameters',
76	        });
77	        return;
78	      }
79	
80	      const statusCode = (stored._statusCode as number) ?? 0;
81	      if (statusCode > 0) {
82	        // Completed — replay
83	        const body = stored._body ?? {};
84	        res.status(statusCode).json(body);
85	        return;
86	      }
87	      // statusCode 0 = still processing first request; wait briefly then re-check
88	      await new Promise((r) => setTimeout(r, 200));
89	      const refreshed = await prisma.idempotencyKey.findUnique({ where: { key: idempotencyKey } });
90	      if (refreshed) {
91	        const ref = refreshed.responseBody as Record<string, unknown>;
92	        const sc = (ref._statusCode as number) ?? 0;
93	        if (sc > 0) {
94	          res.status(sc).json(ref._body ?? {});
95	          return;
96	        }
97	      }
98	      // Still processing — let it through (dedup is best-effort for concurrent requests)
99	    }
100	
101	    // Reserve the key with fingerprint BEFORE processing to prevent races
102	    await prisma.idempotencyKey.upsert({
103	      where: { key: idempotencyKey },
104	      update: {
105	        responseBody: { _fingerprint: fingerprint, _statusCode: 0, _body: null } as unknown as Prisma.InputJsonValue,
106	        expiresAt: new Date(Date.now() + TTL_MS),
107	      },
108	      create: {
109	        key: idempotencyKey,
110	        operationType: `${req.method} ${req.originalUrl.replace(/[0-9a-f-]{36}/gi, ':id')}`,
111	        responseBody: { _fingerprint: fingerprint, _statusCode: 0, _body: null } as unknown as Prisma.InputJsonValue,
112	        expiresAt: new Date(Date.now() + TTL_MS),
113	      },
114	    });
115	
116	    // Intercept response to update the stored record with actual result
117	    const originalJson = res.json.bind(res);
118	
119	    res.json = function interceptJson(body: unknown): Response {
120	      const record = {
121	        _statusCode: res.statusCode,
122	        _body: redactSecrets(body),
123	        _fingerprint: fingerprint,
124	      };
125	      // Update the reserved key with the actual response (fire-and-forget is OK now since key is already reserved)
126	      prisma.idempotencyKey.update({
127	        where: { key: idempotencyKey },
128	        data: { responseBody: record as unknown as Prisma.InputJsonValue },
129	      }).catch((err) => {
130	        logger.error('Failed to update idempotency key', { error: (err as Error).message });
131	      });
132	      return originalJson(body);
133	    };
134	
135	    next();
136	  } catch (err) {
137	    logger.error('Idempotency middleware error', { error: (err as Error).message });
138	    next();
139	  }
140	}
