1	import { Request, Response, NextFunction } from 'express';
2	import { verifyAccessToken } from '../services/auth.service';
3	import { getUserPermissions } from '../services/rbac.service';
4	import { getPrisma } from '../config/database';
5	import { AppError, UNAUTHORIZED, FORBIDDEN } from '../utils/errors';
6	import { JwtPayload } from '../types/auth.types';
7	
8	declare global {
9	  namespace Express {
10	    interface Request {
11	      user?: JwtPayload;
12	      permissions?: string[];
13	    }
14	  }
15	}
16	
17	export async function authMiddleware(req: Request, _res: Response, next: NextFunction): Promise<void> {
18	  const header = req.headers.authorization;
19	  if (!header || !header.startsWith('Bearer ')) {
20	    next(new AppError(401, UNAUTHORIZED, 'Authentication required'));
21	    return;
22	  }
23	
24	  const token = header.slice(7);
25	  try {
26	    const payload = verifyAccessToken(token);
27	
28	    const prisma = getPrisma();
29	    const user = await prisma.user.findUnique({ where: { id: payload.userId } });
30	
31	    if (!user) {
32	      next(new AppError(401, UNAUTHORIZED, 'User not found'));
33	      return;
34	    }
35	
36	    if (user.status !== 'active') {
37	      next(new AppError(403, FORBIDDEN, 'Account is not active'));
38	      return;
39	    }
40	
41	    req.user = { ...payload, role: user.role as JwtPayload['role'] };
42	    next();
43	  } catch (err) {
44	    next(err);
45	  }
46	}
47	
48	export function requireRole(...roles: string[]) {
49	  return (req: Request, _res: Response, next: NextFunction): void => {
50	    if (!req.user) {
51	      next(new AppError(401, UNAUTHORIZED, 'Authentication required'));
52	      return;
53	    }
54	
55	    if (!roles.includes(req.user.role)) {
56	      next(new AppError(403, FORBIDDEN, 'Insufficient role'));
57	      return;
58	    }
59	
60	    next();
61	  };
62	}
63	
64	export function requirePermission(code: string) {
65	  return async (req: Request, _res: Response, next: NextFunction): Promise<void> => {
66	    if (!req.user) {
67	      next(new AppError(401, UNAUTHORIZED, 'Authentication required'));
68	      return;
69	    }
70	
71	    try {
72	      // Admin role bypasses permission checks
73	      if (req.user.role === 'admin') {
74	        next();
75	        return;
76	      }
77	
78	      if (!req.permissions) {
79	        req.permissions = await getUserPermissions(req.user.userId);
80	      }
81	
82	      if (!req.permissions.includes(code)) {
83	        next(new AppError(403, FORBIDDEN, `Missing permission: ${code}`));
84	        return;
85	      }
86	
87	      next();
88	    } catch (err) {
89	      next(err);
90	    }
91	  };
92	}
