1	import express, { Request, Response, NextFunction } from 'express';
2	import helmet from 'helmet';
3	import compression from 'compression';
4	import swaggerUi from 'swagger-ui-express';
5	import { auditMiddleware } from './middleware/audit.middleware';
6	import { idempotencyMiddleware } from './middleware/idempotency.middleware';
7	import authRoutes from './routes/auth.routes';
8	import usersRoutes from './routes/users.routes';
9	import { rolesRouter, permissionPointsRouter, menusRouter, userRolesRouter } from './routes/rbac.routes';
10	import resourcesRoutes, { travelTimesRouter } from './routes/resources.routes';
11	import itinerariesRoutes, { sharedRouter } from './routes/itineraries.routes';
12	import importRoutes from './routes/import.routes';
13	import modelsRoutes from './routes/models.routes';
14	import notificationsRoutes from './routes/notifications.routes';
15	import auditRoutes from './routes/audit.routes';
16	import { AppError, NOT_FOUND, INTERNAL_ERROR } from './utils/errors';
17	import { logger, getTraceId } from './utils/logger';
18	import { apiSpec } from './config/swagger';
19	
20	const app = express();
21	
22	app.use(helmet());
23	app.use(compression());
24	app.use(express.json());
25	
26	app.use(auditMiddleware);
27	app.use(idempotencyMiddleware);
28	
29	app.get('/health', (_req: Request, res: Response) => {
30	  res.json({ status: 'ok', timestamp: new Date().toISOString() });
31	});
32	
33	app.use('/api/docs', swaggerUi.serve, swaggerUi.setup(apiSpec));
34	
35	app.use('/auth', authRoutes);
36	app.use('/users', usersRoutes);
37	app.use('/roles', rolesRouter);
38	app.use('/permission-points', permissionPointsRouter);
39	app.use('/menus', menusRouter);
40	app.use('/users', userRolesRouter);
41	app.use('/resources', resourcesRoutes);
42	app.use('/travel-times', travelTimesRouter);
43	app.use('/itineraries', itinerariesRoutes);
44	app.use('/', sharedRouter);
45	app.use('/', importRoutes);
46	app.use('/models', modelsRoutes);
47	app.use('/', notificationsRoutes);
48	app.use('/', auditRoutes);
49	
50	app.use((_req: Request, _res: Response, next: NextFunction) => {
51	  next(new AppError(404, NOT_FOUND, 'Resource not found'));
52	});
53	
54	app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
55	  if (err instanceof AppError) {
56	    const body: Record<string, unknown> = {
57	      statusCode: err.statusCode,
58	      code: err.code,
59	      message: err.message,
60	      traceId: getTraceId(),
61	    };
62	    if (err.details !== undefined) {
63	      body.details = err.details;
64	    }
65	    res.status(err.statusCode).json(body);
66	    return;
67	  }
68	
69	  logger.error('unhandled error', {
70	    error: err.message,
71	    stack: err.stack,
72	  });
73	
74	  res.status(500).json({
75	    statusCode: 500,
76	    code: INTERNAL_ERROR,
77	    message: 'Internal server error',
78	    traceId: getTraceId(),
79	  });
80	});
81	
82	export default app;
