1	import bcrypt from 'bcryptjs';
2	import jwt from 'jsonwebtoken';
3	import { v4 as uuidv4 } from 'uuid';
4	import { getPrisma } from '../config/database';
5	import { env } from '../config/environment';
6	import { authConfig } from '../config/auth';
7	import { encrypt, decrypt, hashSha256 } from '../utils/crypto';
8	import { AppError, VALIDATION_ERROR, UNAUTHORIZED, CONFLICT, NOT_FOUND, RATE_LIMITED } from '../utils/errors';
9	import { JwtPayload, TokenPair, UserRole } from '../types/auth.types';
10	
11	const BCRYPT_ROUNDS = 12;
12	const MAX_DEVICES = 5;
13	const MAX_FAILED_ATTEMPTS = 10;
14	const LOCKOUT_MINUTES = 15;
15	const PASSWORD_HISTORY_COUNT = 5;
16	
17	export function validatePasswordPolicy(password: string): void {
18	  if (password.length < 12) {
19	    throw new AppError(400, VALIDATION_ERROR, 'Password must be at least 12 characters');
20	  }
21	  if (!/[A-Z]/.test(password)) {
22	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one uppercase letter');
23	  }
24	  if (!/[a-z]/.test(password)) {
25	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one lowercase letter');
26	  }
27	  if (!/[0-9]/.test(password)) {
28	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one digit');
29	  }
30	  if (!/[^A-Za-z0-9]/.test(password)) {
31	    throw new AppError(400, VALIDATION_ERROR, 'Password must contain at least one special character');
32	  }
33	}
34	
35	export function signAccessToken(payload: Omit<JwtPayload, 'iat' | 'exp'>): string {
36	  return jwt.sign(payload, env.jwtSecret, {
37	    algorithm: authConfig.algorithm,
38	    expiresIn: authConfig.accessTokenTtl,
39	  });
40	}
41	
42	export function signRefreshToken(): string {
43	  return uuidv4() + '-' + uuidv4();
44	}
45	
46	export function verifyAccessToken(token: string): JwtPayload {
47	  try {
48	    return jwt.verify(token, env.jwtSecret, {
49	      algorithms: [authConfig.algorithm],
50	    }) as JwtPayload;
51	  } catch {
52	    throw new AppError(401, UNAUTHORIZED, 'Invalid or expired token');
53	  }
54	}
55	
56	export async function register(
57	  username: string,
58	  password: string,
59	  securityQuestions: Array<{ question: string; answer: string }>,
60	): Promise<{ id: string; username: string }> {
61	  const prisma = getPrisma();
62	
63	  validatePasswordPolicy(password);
64	
65	  if (!securityQuestions || securityQuestions.length !== 2) {
66	    throw new AppError(400, VALIDATION_ERROR, 'Exactly 2 security questions are required');
67	  }
68	
69	  const existing = await prisma.user.findUnique({ where: { username } });
70	  if (existing) {
71	    throw new AppError(409, CONFLICT, 'Username already taken');
72	  }
73	
74	  const passwordHash = await bcrypt.hash(password, BCRYPT_ROUNDS);
75	
76	  const user = await prisma.user.create({
77	    data: {
78	      username,
79	      passwordHash,
80	      securityQuestions: {
81	        create: securityQuestions.map((sq) => ({
82	          question: sq.question,
83	          answerEncrypted: encrypt(sq.answer.trim().toLowerCase()),
84	        })),
85	      },
86	      passwordHistory: {
87	        create: { passwordHash },
88	      },
89	    },
90	  });
91	
92	  return { id: user.id, username: user.username };
93	}
94	
95	export async function login(
96	  username: string,
97	  password: string,
98	  deviceFingerprint?: string,
99	  lastKnownCity?: string,
100	  challengeToken?: string,
101	): Promise<{ tokens: TokenPair; user: { id: string; username: string; role: string } } | { challengeToken: string; retryAfterSeconds: number; message: string }> {
102	  const prisma = getPrisma();
103	
104	  const user = await prisma.user.findUnique({ where: { username } });
105	  if (!user) {
106	    throw new AppError(401, UNAUTHORIZED, 'Invalid credentials');
107	  }
108	
109	  // Rolling lockout: auto-unlock if lock window has expired
110	  if (user.lockedUntil && user.lockedUntil <= new Date()) {
111	    await prisma.user.update({
112	      where: { id: user.id },
113	      data: { lockedUntil: null, status: 'active' },
114	    });
115	    user.lockedUntil = null;
116	    user.status = 'active';
117	  }
118	
119	  if (user.status === 'locked' || (user.lockedUntil && user.lockedUntil > new Date())) {
120	    throw new AppError(423, 'ACCOUNT_LOCKED', 'Account is locked. Try again later.');
121	  }
122	
123	  if (user.status === 'suspended') {
124	    throw new AppError(403, 'FORBIDDEN', 'Account is suspended');
125	  }
126	
127	  const valid = await bcrypt.compare(password, user.passwordHash);
128	  if (!valid) {
129	    // Record the failed attempt
130	    await prisma.loginAttempt.create({
131	      data: { userId: user.id, success: false },
132	    });
133	
134	    // Count failures in the rolling 15-minute window
135	    const windowStart = new Date(Date.now() - LOCKOUT_MINUTES * 60 * 1000);
136	    const recentFailures = await prisma.loginAttempt.count({
137	      where: {
138	        userId: user.id,
139	        success: false,
140	        createdAt: { gte: windowStart },
141	      },
142	    });
143	
144	    if (recentFailures >= MAX_FAILED_ATTEMPTS) {
145	      const lockUntil = new Date(Date.now() + LOCKOUT_MINUTES * 60 * 1000);
146	      await prisma.user.update({
147	        where: { id: user.id },
148	        data: { lockedUntil: lockUntil, status: 'locked' },
149	      });
150	    }
151	
152	    throw new AppError(401, UNAUTHORIZED, 'Invalid credentials');
153	  }
154	
155	  // Successful login — record it and clear lock state
156	  await prisma.loginAttempt.create({
157	    data: { userId: user.id, success: true },
158	  });
159	  if (user.status === 'locked' || user.lockedUntil) {
160	    await prisma.user.update({
161	      where: { id: user.id },
162	      data: { lockedUntil: null, status: 'active' },
163	    });
164	  }
165	
166	  // Device registration
167	  const fpHash = deviceFingerprint
168	    ? hashSha256(deviceFingerprint)
169	    : hashSha256(uuidv4());
170	
171	  let device = await prisma.device.findUnique({
172	    where: { userId_fingerprintHash: { userId: user.id, fingerprintHash: fpHash } },
173	  });
174	
175	  if (!device) {
176	    const deviceCount = await prisma.device.count({ where: { userId: user.id } });
177	    if (deviceCount >= MAX_DEVICES) {
178	      // Return 409 with device list so client can prompt removal
179	      const existingDevices = await prisma.device.findMany({
180	        where: { userId: user.id },
181	        select: { id: true, lastSeenAt: true, lastKnownCity: true, createdAt: true },
182	        orderBy: { lastSeenAt: 'desc' },
183	      });
184	      throw new AppError(
185	        409,
186	        'DEVICE_LIMIT_REACHED',
187	        `Maximum ${MAX_DEVICES} devices allowed. Remove a device first.`,
188	        { devices: existingDevices },
189	      );
190	    }
191	
192	    device = await prisma.device.create({
193	      data: {
194	        userId: user.id,
195	        fingerprintHash: fpHash,
196	        lastSeenAt: new Date(),
197	        lastKnownCity: lastKnownCity || null,
198	      },
199	    });
200	  } else {
201	    // If challengeToken provided, validate it and skip location check
202	    if (challengeToken) {
203	      // Find the per-attempt challenge record by token
204	      const attemptKey = `challenge:${user.id}:${fpHash}:${challengeToken}`;
205	      const challenge = await prisma.idempotencyKey.findUnique({ where: { key: attemptKey } });
206	      if (!challenge || challenge.expiresAt < new Date() || challenge.operationType !== 'location_challenge') {
207	        throw new AppError(401, UNAUTHORIZED, 'Invalid or expired challenge token');
208	      }
209	      // Consume the challenge token (one-time use)
210	      await prisma.idempotencyKey.delete({ where: { key: attemptKey } });
211	      // Update device city
212	      await prisma.device.update({
213	        where: { id: device.id },
214	        data: { lastSeenAt: new Date(), lastKnownCity },
215	      });
216	    } else if (
217	      lastKnownCity &&
218	      device.lastKnownCity &&
219	      lastKnownCity.trim().toLowerCase() !== device.lastKnownCity.trim().toLowerCase()
220	    ) {
221	      // Unusual location detection — issue a challenge token
222	      const oneHourAgo = new Date(Date.now() - 60 * 60 * 1000);
223	
224	      // Rate limit: count per-attempt challenge rows in the last rolling hour
225	      const recentChallenges = await prisma.idempotencyKey.findMany({
226	        where: {
227	          key: { startsWith: `challenge:${user.id}:${fpHash}:` },
228	          operationType: 'location_challenge',
229	          createdAt: { gte: oneHourAgo },
230	        },
231	      });
232	
233	      if (recentChallenges.length >= 3) {
234	        // Find the oldest challenge in the window to compute retryAfter
235	        const oldest = recentChallenges.reduce((a, b) =>
236	          a.createdAt < b.createdAt ? a : b,
237	        );
238	        const retryAfterSeconds = Math.max(1, Math.ceil((oldest.createdAt.getTime() + 3600000 - Date.now()) / 1000));
239	        throw new AppError(429, RATE_LIMITED, `Too many challenge attempts. Retry after ${retryAfterSeconds} seconds.`);
240	      }
241	
242	      // Generate unique per-attempt challenge token
243	      const newChallengeToken = uuidv4();
244	      const attemptKey = `challenge:${user.id}:${fpHash}:${newChallengeToken}`;
245	
246	      await prisma.idempotencyKey.create({
247	        data: {
248	          key: attemptKey,
249	          operationType: 'location_challenge',
250	          responseBody: {
251	            challengeToken: newChallengeToken,
252	            cityFrom: device.lastKnownCity,
253	            cityTo: lastKnownCity,
254	          },
255	          expiresAt: new Date(Date.now() + 5 * 60 * 1000), // 5-minute TTL
256	        },
257	      });
258	
259	      return {
260	        challengeToken: newChallengeToken,
