131	        VALIDATION_ERROR,
132	        `Resource is closed on this date${closure.reason ? ': ' + closure.reason : ''}`,
133	      );
134	    }
135	
136	    // 3. Business hours check
137	    const dayOfWeek = actualDate.getDay();
138	    const hoursForDay = resource.hours.filter((h) => h.dayOfWeek === dayOfWeek);
139	    if (hoursForDay.length > 0) {
140	      const withinAnyWindow = hoursForDay.some((h) => {
141	        const openMin = timeToMinutes(h.openTime);
142	        const closeMin = timeToMinutes(h.closeTime);
143	        return startMin >= openMin && endMin <= closeMin;
144	      });
145	      if (!withinAnyWindow) {
146	        throw new AppError(400, VALIDATION_ERROR, 'Item time falls outside business hours');
147	      }
148	    }
149	  }
150	
151	  // 4. Load existing items on same day for overlap / buffer / travel checks
152	  const existingItems = await prisma.itineraryItem.findMany({
153	    where: {
154	      itineraryId,
155	      dayNumber,
156	      ...(excludeItemId ? { id: { not: excludeItemId } } : {}),
157	    },
158	    include: { resource: true },
159	    orderBy: { startTime: 'asc' },
160	  });
161	
162	  const BUFFER_MINUTES = 15;
