1	import request from 'supertest';
2	import { v4 as uuid } from 'uuid';
3	import app from '../src/app';
4	import { getPrisma } from '../src/config/database';
5	
6	const prisma = getPrisma();
7	
8	const ts = Date.now();
9	const adminCreds = { username: `rbac_admin_${ts}`, password: 'AdminPass123!x' };
10	const orgCreds = { username: `rbac_org_${ts}`, password: 'OrgPass12345!x' };
11	
12	let adminToken: string;
13	let orgToken: string;
14	let adminUserId: string;
15	let orgUserId: string;
16	let roleId: string;
17	let ppId: string;
18	
19	beforeAll(async () => {
20	  await prisma.$connect();
21	
22	  // Register admin user
23	  const adminReg = await request(app).post('/auth/register').set('Idempotency-Key', uuid()).send({
24	    ...adminCreds,
25	    securityQuestions: [
26	      { question: 'Q1?', answer: 'a1' },
27	      { question: 'Q2?', answer: 'a2' },
28	    ],
29	  });
30	  adminUserId = adminReg.body.id;
31	
32	  // Promote to admin role in DB
33	  await prisma.user.update({
34	    where: { id: adminUserId },
35	    data: { role: 'admin' },
36	  });
37	
38	  // Login as admin
39	  const adminLogin = await request(app).post('/auth/login').set('Idempotency-Key', uuid()).send(adminCreds);
40	  adminToken = adminLogin.body.accessToken;
41	
42	  // Register organizer user
43	  const orgReg = await request(app).post('/auth/register').set('Idempotency-Key', uuid()).send({
44	    ...orgCreds,
45	    securityQuestions: [
46	      { question: 'Q1?', answer: 'a1' },
47	      { question: 'Q2?', answer: 'a2' },
48	    ],
49	  });
50	  orgUserId = orgReg.body.id;
51	
52	  // Login as organizer
53	  const orgLogin = await request(app).post('/auth/login').set('Idempotency-Key', uuid()).send(orgCreds);
54	  orgToken = orgLogin.body.accessToken;
55	});
56	
57	afterAll(async () => {
58	  // Clean up test data
59	  for (const uid of [adminUserId, orgUserId]) {
60	    if (!uid) continue;
61	    await prisma.refreshToken.deleteMany({ where: { userId: uid } });
62	    await prisma.device.deleteMany({ where: { userId: uid } });
63	    await prisma.securityQuestion.deleteMany({ where: { userId: uid } });
64	    await prisma.passwordHistory.deleteMany({ where: { userId: uid } });
65	    await prisma.userRole.deleteMany({ where: { userId: uid } });
66	  }
67	  if (roleId) {
68	    await prisma.rolePermissionPoint.deleteMany({ where: { roleId } });
69	    await prisma.role.deleteMany({ where: { id: roleId } });
70	  }
71	  if (ppId) {
72	    await prisma.permissionPoint.deleteMany({ where: { id: ppId } });
73	  }
74	  for (const uid of [adminUserId, orgUserId]) {
75	    if (!uid) continue;
76	    await prisma.user.deleteMany({ where: { id: uid } });
77	  }
78	  await prisma.$disconnect();
79	});
